class Solution {
    TreeNode* prev = nullptr;
    void dfs(TreeNode* nd) {
        if (!nd) return;
        dfs(nd->right);
        dfs(nd->left);
        nd->right = prev;
        nd->left = nullptr;
        prev = nd;
    }
public:
    void flatten(TreeNode* root) {
        dfs(root);
    }
};
